noncompliant:
// Noncompliant: jumping into a for loop
void f1(int a) {
    if (a <= 0) {
        goto L2;  // Noncompliant: jumping into for loop
    }

    for (int i = 0; i < 10; i++) {
        L2:
            printf("Value: %d\n", i);
    }
}

// Noncompliant: jumping into if block
void f2(int x) {
    if (x > 0) {
        goto inside_if;  // Noncompliant
    }

    if (some_condition) {
        inside_if:
            // code here
    }
}

compliant:
// Compliant: structured control flow
void f1(int a) {
    if (a > 0) {
        for (int i = 0; i < 10; i++) {
            printf("Value: %d\n", i);
        }
    }
}

// Compliant: forward jump to cleanup (not into block)
void f2() {
    if (error_condition) {
        goto cleanup;
    }

    // normal processing

    cleanup:
        // cleanup code
}
